<?php namespace App\Repositories\Health;use App\Repositories\BaseRepository;use App\Models\Health\HealthRecord;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class HealthRecordRepository extends BaseRepository{    public function __construct(HealthRecord $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByCheckupType(string $type): Collection    {        return $this->findByField('checkup_type', $type);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('checkup_date', [$startDate, $endDate])->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function getByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function searchRecords(string $keyword): Collection    {        return $this->query()->where('remarks', 'like', "%{$keyword}%")->orWhere('diagnosis', 'like', "%{$keyword}%")->get();    }    public function getByCondition(string $condition): Collection    {        return $this->query()->where('diagnosis', 'like', "%{$condition}%")->get();    }    public function getLatestByStudent(int $studentId): ?HealthRecord    {        return $this->query()->where('student_id', $studentId)->orderBy('checkup_date', 'desc')->first();    }}